import{_ as a,o as i,c as e,a2 as l}from"./chunks/framework.Fbjs98zA.js";const u=JSON.parse('{"title":"Mango Issue 登记与处理 Runbook","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/07-mango-issue-runbook.md","filePath":"mango-pmo/rules/07-mango-issue-runbook.md"}'),n={name:"mango-pmo/rules/07-mango-issue-runbook.md"};function t(p,s,h,o,d,r){return i(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="mango-issue-登记与处理-runbook" tabindex="-1">Mango Issue 登记与处理 Runbook <a class="header-anchor" href="#mango-issue-登记与处理-runbook" aria-label="Permalink to &quot;Mango Issue 登记与处理 Runbook&quot;">​</a></h1><h2 id="_1-触发条件" tabindex="-1">1. 触发条件 <a class="header-anchor" href="#_1-触发条件" aria-label="Permalink to &quot;1. 触发条件&quot;">​</a></h2><p>业务开发使用 Mango 时，确认问题由 Mango 框架、starter、CLI、模板、前端包或发布物料引起，必须登记 Mango Issue。</p><p>非缺陷类建议也必须登记 Issue，并标记为建议。</p><p>处理已有 Mango Issue 时，必须先按本文件的处理流程确认事实和现状，再决定是否进入修复、验证、关闭或补充信息。</p><h2 id="_2-仓库" tabindex="-1">2. 仓库 <a class="header-anchor" href="#_2-仓库" aria-label="Permalink to &quot;2. 仓库&quot;">​</a></h2><p>Mango Issue 统一提交到：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https://github.com/HardyDou/mango/issues</span></span></code></pre></div><h2 id="_3-标题" tabindex="-1">3. 标题 <a class="header-anchor" href="#_3-标题" aria-label="Permalink to &quot;3. 标题&quot;">​</a></h2><p>标题格式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P0|P1|P2: &lt;影响对象&gt; &lt;问题摘要&gt;</span></span></code></pre></div><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>P0: Mango Flyway migration blocks upgraded business backend startup</span></span>
<span class="line"><span>P1: Generated mango.dev.json does not adapt to renamed business app folders</span></span></code></pre></div><h2 id="_4-标签" tabindex="-1">4. 标签 <a class="header-anchor" href="#_4-标签" aria-label="Permalink to &quot;4. 标签&quot;">​</a></h2><ul><li>缺陷：<code>bug</code></li><li>能力优化：<code>enhancement</code></li><li>文档或流程：<code>documentation</code></li><li>信息不足：<code>question</code></li></ul><p>没有合适标签时，先用最接近标签，不得因为标签不全而不登记 Issue。</p><h2 id="_5-优先级" tabindex="-1">5. 优先级 <a class="header-anchor" href="#_5-优先级" aria-label="Permalink to &quot;5. 优先级&quot;">​</a></h2><ul><li><code>P0</code>：阻断服务启动、构建、发布、登录、核心验收或数据安全。</li><li><code>P1</code>：不阻断主流程，但导致业务升级、开发、验证明显不稳定或需要人工绕行。</li><li><code>P2</code>：体验优化、文档补充、低风险建议。</li></ul><h2 id="_6-证据" tabindex="-1">6. 证据 <a class="header-anchor" href="#_6-证据" aria-label="Permalink to &quot;6. 证据&quot;">​</a></h2><p>Issue body 必须包含：</p><ul><li>Mango 版本：CLI、npm 包、Maven 依赖或 Git commit。</li><li>消费项目场景：业务项目名称、启动方式、命令。</li><li>复现步骤：最少可复核步骤。</li><li>实际结果：错误日志、截图、命令输出或失败断言。</li><li>期望结果：Mango 应提供的行为。</li><li>影响范围：阻断、绕行成本、涉及模块。</li><li>业务任务记录：当前业务任务中登记 Issue 地址和阻塞状态。</li></ul><p>日志和截图放在业务任务证据目录；Issue 中只贴关键摘要和证据路径，禁止上传密码、token、密钥、客户敏感数据。</p><h2 id="_7-命令" tabindex="-1">7. 命令 <a class="header-anchor" href="#_7-命令" aria-label="Permalink to &quot;7. 命令&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> issue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HardyDou/mango</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;P1: &lt;影响对象&gt; &lt;问题摘要&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --label</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --body-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/issue-body.md</span></span></code></pre></div><p>紧急问题可直接写 body：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> issue</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HardyDou/mango</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;P0: &lt;影响对象&gt; &lt;问题摘要&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --label</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --body</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;## 现象</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">...</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">## 影响</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">P0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">## 证据</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">...&quot;</span></span></code></pre></div><h2 id="_8-处理已有-issue" tabindex="-1">8. 处理已有 Issue <a class="header-anchor" href="#_8-处理已有-issue" aria-label="Permalink to &quot;8. 处理已有 Issue&quot;">​</a></h2><p>接到“处理 Issue / 修复 Issue / 关闭 Issue / Issue #xxx”任务时，必须先加载 Issue 信息，不得在未知 Issue 内容和影响范围时直接进入开发 preflight 或修改代码。</p><p>必须执行：</p><ol><li>读取 Issue 标题、正文、标签、状态、评论、关联 PR、最新相关提交和当前分支状态。</li><li>判断 Issue 类型：缺陷、能力优化、文档流程、信息不足或已完成待关闭。</li><li>判断问题是否仍存在：检查 <code>main</code>、相关发布物料、关联 PR 和本地代码；不能仅凭记忆判断。</li><li>判断是否可复现：能复现时记录复现命令、环境、数据、日志或截图；不能复现时记录缺失条件和需要补充的信息。</li><li>判断是否已被修复：如已修复，必须给出修复来源、版本或提交依据，并执行可行的回归验证后再建议关闭。</li><li>判断影响范围：明确涉及路径、模块、接口、数据库、前端页面、测试、文档或发布物料。</li><li>制定处理方案：关闭、补充信息、复现验证、修复、回归、发布或转为新 Issue。</li><li>只有确定需要修改受版本控制文件、形成验证结论、发布、提交或 PR 时，才按明确的 role、phase、task 和 paths 执行 PMO preflight，并读取输出的 Must read。</li><li>preflight 输出 <code>worktree-required</code> 时，必须先创建或复用任务 worktree 后再改服务代码、接口、数据库、测试、前端页面或构建配置。</li></ol><p>禁止：</p><ul><li>未读取 Issue 内容就直接按猜测修复。</li><li>未判断问题是否仍存在就创建分支或改代码。</li><li>未复现或未说明不可复现原因就声明修复完成。</li><li>已被修复的问题重复改代码。</li><li>用登记 Issue 流程替代处理已有 Issue 流程。</li></ul><h2 id="_9-后续处理" tabindex="-1">9. 后续处理 <a class="header-anchor" href="#_9-后续处理" aria-label="Permalink to &quot;9. 后续处理&quot;">​</a></h2><ul><li>Issue 创建后，必须把 URL 写回当前业务任务记录。</li><li>Mango 缺陷阻塞当前模块且没有同等质量替代方案时，暂停该模块开发。</li><li>当前任务结束时，必须提醒开发者根据 Issue 结论决定升级 Mango、更换方案或调整业务计划。</li></ul>`,34)])])}const c=a(n,[["render",t]]);export{u as __pageData,c as default};
